// Feign Client
@FeignClient(name = "inventory-service")
public interface InventoryClient {
  @GetMapping("/api/inventory/{sku}")
  InventoryResponse check(@PathVariable String sku);
}

// Circuit Breaker with Resilience4j
@CircuitBreaker(name = "inventory", fallbackMethod = "fallback")
public InventoryResponse getInventory(String sku) {
  return inventoryClient.check(sku);
}

public InventoryResponse fallback(String sku, Exception ex) {
  return InventoryResponse.unavailable();
}

